module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                    clk,
    input  logic                    rst_n,
    input  logic                    enable,
    input  logic                    clear,
    input  logic [STEP_WIDTH-1:0]   step,
    output logic [COUNT_WIDTH-1:0]  count,
    output logic                    wrapped,
    output logic                    valid
);

    // Architectural state mapped to function_model state_variables.
    logic [COUNT_WIDTH-1:0] count_q;
    logic                   wrapped_q;
    logic                   valid_q;

    // Evidence-backed handshake naming for clear-enable priority rule.
    logic clear_enable_priority;

    // 9-bit style carry capture generalized to COUNT_WIDTH+1.
    logic [COUNT_WIDTH:0] step_ext;
    logic [COUNT_WIDTH:0] sum_ext;

    assign clear_enable_priority = clear & enable;
    assign step_ext = {{(COUNT_WIDTH-STEP_WIDTH+1){1'b0}}, step};
    assign sum_ext  = {1'b0, count_q} + step_ext;

    // SAMPLE/COMMIT latency-1 contract:
    // inputs are sampled at this rising edge and COMMIT-visible outputs/state
    // are updated by this same edge (visible immediately after edge N).
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            // Reset dominance: asynchronous assert, synchronous release behavior.
            count_q   <= {COUNT_WIDTH{1'b0}};
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else if (clear_enable_priority || clear) begin
            // clear has priority over enable when both are sampled high.
            count_q   <= {COUNT_WIDTH{1'b0}};
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else if (enable) begin
            // Enabled modulo increment; wrapped is carry-out pulse; valid is update pulse.
            count_q   <= sum_ext[COUNT_WIDTH-1:0];
            wrapped_q <= sum_ext[COUNT_WIDTH];
            valid_q   <= 1'b1;
        end else begin
            // No backpressure path in this IP: idle holds count, pulses deassert.
            count_q   <= count_q;
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end
    end

    // Observability: each FM transaction maps directly to COMMIT-stage outputs.
    assign count   = count_q;
    assign wrapped = wrapped_q;
    assign valid   = valid_q;

endmodule

